-- Ghana Tertiary UniConnect Dataset - part 8
-- Run parts sequentially in Supabase SQL Editor.

insert into public.departments (source_id, university_id, faculty_id, name) select 'gctu_arts_humanities_and_social_sciences_languages', u.id, f.id, 'Languages' from public.universities u join public.faculties f on f.source_id = 'gctu_arts_humanities_and_social_sciences' where u.source_id = 'gctu' and not exists (select 1 from public.departments where source_id = 'gctu_arts_humanities_and_social_sciences_languages' or (university_id = u.id and name = 'Languages'));
update public.departments set source_id = coalesce(source_id, 'gctu_arts_humanities_and_social_sciences_languages'), faculty_id = (select id from public.faculties where source_id = 'gctu_arts_humanities_and_social_sciences') where source_id = 'gctu_arts_humanities_and_social_sciences_languages' or (name = 'Languages' and university_id = (select id from public.universities where source_id = 'gctu'));
